{"command": "cd /mnt/d/PycharmProjects/AutoMD && python3 -c "
import parmed as pmd
# 检查complex.prmtop
try:
    struct = pmd.load_file('output/md/complex.prmtop', 'output/md/complex.inpcrd')
    print(f'complex.prmtop: {len(struct.atoms)} atoms, {len(struct.residues)} residues')
    for res in struct.residues:
        print(f'  Residue: {res.name} (chain {res.chain})')
except Exception as e:
    print(f'Error loading complex: {e}')

print()
# 检查complex_with_lig
try:
    struct2 = pmd.load_file('output/md/complex_with_lig.prmtop', 'output/md/complex_with_lig.inpcrd')
    print(f'complex_with_lig.prmtop: {len(struct2.atoms)} atoms, {len(struct2.residues)} residues')
    for res in struct2.residues:
        print(f'  Residue: {res.name} (chain {res.chain})')
except Exception as e:
    print(f'Error loading complex_with_lig: {e}')
"
"}

